// --- 1. Backend API Service (Mock for demonstration) ---
// In a real application, this would interact with your actual backend server.
// Your backend is CRITICAL for security and PCI compliance.
class BackendApiService {
  // Simulates creating a Stripe PaymentIntent on your backend.
  // The client_secret is returned to the Flutter app to finalize the payment.
  static Future<Map<String, dynamic>> createPaymentIntent({
    required int amount,
    required String currency,
  }) async {
    final url = Uri.parse('$BACKEND_BASE_URL/create-payment-intent');
    try {
      final response = await http.post(
        url,
        headers: {'Content-Type': 'application/json'},
        body: json.encode({
          'amount': amount, // in cents
          'currency': currency,
        }),
      );

      if (response.statusCode == 200) {
        return json.decode(response.body);
      } else {
        throw Exception('Failed to create PaymentIntent on backend: ${response.body}');
      }
    } catch (e) {
      throw Exception('Error communicating with backend for PaymentIntent: $e');
    }
  }

  // Verifies an In-App Purchase receipt/token on your backend with the App Store/Google Play.
  // This is CRITICAL to prevent fraud and ensure content delivery.
  static Future<Map<String, dynamic>> verifyInAppPurchase({
    required String platform, // 'ios' or 'android'
    required String productId,
    required String verificationData, // receipt or purchase token
    String? transactionId, // For iOS, optional for Android
  }) async {
    final url = Uri.parse('$BACKEND_BASE_URL/verify-iap');
    try {
      final response = await http.post(
        url,
        headers: {'Content-Type': 'application/json'},
        body: json.encode({
          'platform': platform,
          'productId': productId,
          'verificationData': verificationData,
          'transactionId': transactionId,
        }),
      );

      if (response.statusCode == 200) {
        return json.decode(response.body);
      } else {
        throw Exception('Failed to verify IAP on backend: ${response.body}');
      }
    } catch (e) {
      throw Exception('Error communicating with backend for IAP verification: $e');
    }
  }

  // Acknowledges an In-App Purchase on your backend (specifically for Android).
  // Google Play requires purchases to be acknowledged within 3 days.
  static Future<void> acknowledgePurchase({
    required String platform,
    required String purchaseToken,
    required String productId,
  }) async {
    final url = Uri.parse('$BACKEND_BASE_URL/acknowledge-iap');
    try {
      final response = await http.post(
        url,
        headers: {'Content-Type': 'application/json'},
        body: json.encode({
          'platform': platform,
          'purchaseToken': purchaseToken,
          'productId': productId,
        }),
      );

      if (response.statusCode != 200) {
        throw Exception('Failed to acknowledge IAP on backend: ${response.body}');
      }
    } catch (e) {
      throw Exception('Error communicating with backend for IAP acknowledgment: $e');
    }
  }
}

// --- 2. Stripe Payment Service ---
// Handles credit card and mobile wallet (Apple Pay/Google Pay) payments via Stripe.
// Leverages Stripe's PaymentSheet for PCI compliance and ease of integration.
class StripeService {
  static Future<void> init() async {
    Stripe.publishableKey = STRIPE_PUBLISHABLE_KEY;
    await Stripe.instance.applySettings(); // Optional: Apply any custom settings
  }

  // Processes a card payment using Stripe's PaymentSheet.
  // The PaymentSheet handles UI, card data collection, and confirmation securely.
  static Future<bool> processCardPayment({
    required int amount, // in cents
    required String currency,
  }) async {
    try {
      // 1. Request PaymentIntent client_secret from your backend.
      final paymentIntentData = await BackendApiService.createPaymentIntent(
        amount: amount,
        currency: currency,
      );
      final clientSecret = paymentIntentData['clientSecret'];

      if (clientSecret == null) {
        throw Exception("Failed to get client secret from backend.");
      }

      // 2. Initialize the PaymentSheet with the client_secret.
      await Stripe.instance.initPaymentSheet(
        paymentSheetParameters: SetupPaymentSheetParameters(
          merchantDisplayName: 'Your Company Name',
          paymentIntentClientSecret: clientSecret,
          currencyCode: currency,
          style: ThemeMode.light, // Or ThemeMode.dark
          googlePay: PaymentSheetGooglePay(
            merchantCountryCode: 'US', // Adjust as needed
            testEnv: true, // Set to false for production
          ),
          applePay: PaymentSheetApplePay(
            merchantCountryCode: 'US', // Adjust as needed
          ),
        ),
      );

      // 3. Present the Payment Sheet. This step will handle
      //    card input, securely tokenize the data, and confirm the PaymentIntent.
      await Stripe.instance.presentPaymentSheet();

      print('Card payment successful via PaymentSheet!');
      return true;
    } on StripeException catch (e) {
      print('Error during Stripe PaymentSheet flow: ${e.error.code} - ${e.error.message}');
      if (e.error.code == 'Canceled') {
        print('Payment cancelled by user.');
      }
      return false;
    } catch (e) {
      print('General error during Stripe PaymentSheet flow: $e');
      return false;
    }
  }

  // Processes a mobile wallet payment (Apple Pay / Google Pay) using Stripe's PaymentSheet.
  static Future<bool> processWalletPayment({
    required int amount, // in cents
    required String currency,
  }) async {
    try {
      // 1. Request PaymentIntent client_secret from your backend.
      final paymentIntentData = await BackendApiService.createPaymentIntent(
        amount: amount,
        currency: currency,
      );
      final clientSecret = paymentIntentData['clientSecret'];

      if (clientSecret == null) {
        throw Exception("Failed to get client secret from backend for wallet payment.");
      }

      // 2. Initialize Payment Sheet for wallet payment.
      await Stripe.instance.initPaymentSheet(
        paymentSheetParameters: SetupPaymentSheetParameters(
          merchantDisplayName: 'Your Company Name',
          paymentIntentClientSecret: clientSecret,
          currencyCode: currency,
          googlePay: PaymentSheetGooglePay(
            merchantCountryCode: 'US', // Adjust as needed
            testEnv: true, // Set to false for production
          ),
          applePay: PaymentSheetApplePay(
            merchantCountryCode: 'US', // Adjust as needed
          ),
          style: ThemeMode.light,
        ),
      );

      // 3. Present the Payment Sheet, which will handle the native wallet UI
      //    and confirm the PaymentIntent.
      await Stripe.instance.presentPaymentSheet();

      print('Wallet payment successful!');
      return true;
    } on StripeException catch (e) {
      print('Error during Stripe Wallet Payment: ${e.error.code} - ${e.error.message}');
      if (e.error.code == 'Canceled') {
        print('Wallet payment cancelled by user.');
      }
      return false;
    } catch (e) {
      print('General error during Stripe Wallet Payment: $e');
      return false;
    }
  }
}

// --- 3. In-App Purchase Service ---
// Handles consumable, non-consumable, and subscription in-app purchases.
class IAPService {
  final InAppPurchase _iap = InAppPurchase.instance;
  late StreamSubscription<List<PurchaseDetails>> _purchaseStreamSubscription;

  // IMPORTANT: Replace with your actual product IDs from App Store Connect / Google Play Console.
  static const Set<String> _kProductIds = {
    'com.yourapp.consumable_item_1',
    'com.yourapp.premium_subscription_monthly',
    'com.yourapp.one_time_unlock',
  };

  List<ProductDetails> _availableProducts = [];
  bool _isAvailable = false;
  bool _purchasePending = false; // To prevent multiple simultaneous purchases

  List<ProductDetails> get availableProducts => _availableProducts;
  bool get isAvailable => _isAvailable;
  bool get purchasePending => _purchasePending;

  // Callbacks for UI updates
  Function(PurchaseDetails)? onPurchaseSuccess;
  Function(String)? onPurchaseError;
  Function(bool)? onPurchaseProcessing; // To notify UI about pending state

  Future<void> init() async {
    _isAvailable = await _iap.isAvailable();
    if (!_isAvailable) {
      print('In-App Purchase not available on this device.');
      return;
    }

    _purchaseStreamSubscription = _iap.purchaseStream.listen(
      _listenToPurchaseUpdates,
      onDone: () => _purchaseStreamSubscription.cancel(),
      onError: (error) {
        print('IAP Stream Error: $error');
        onPurchaseError?.call('IAP Stream Error: $error');
        onPurchaseProcessing?.call(false);
      },
    );

    await _loadProducts();
  }

  Future<void> _loadProducts() async {
    final ProductDetailsResponse response = await _iap.queryProductDetails(_kProductIds);
    if (response.error != null) {
      print('Error querying products: ${response.error!.message}');
      onPurchaseError?.call('Error querying products: ${response.error!.message}');
      return;
    }

    _availableProducts = response.productDetails;
    print('Available products: ${_availableProducts.map((p) => p.id).join(', ')}');
  }

  void _listenToPurchaseUpdates(List<PurchaseDetails> purchaseDetailsList) {
    for (final purchase in purchaseDetailsList) {
      if (purchase.status == PurchaseStatus.pending) {
        _handlePending(purchase);
      } else {
        if (purchase.status == PurchaseStatus.error) {
          _handleError(purchase);
        } else if (purchase.status == PurchaseStatus.purchased ||
                   purchase.status == PurchaseStatus.restored) {
          _handleSuccess(purchase);
        }
      }
    }
  }

  void _handlePending(PurchaseDetails purchase) {
    print('Purchase pending: ${purchase.productID}');
    _purchasePending = true;
    onPurchaseProcessing?.call(true);
  }

  void _handleError(PurchaseDetails purchase) {
    print('Purchase error: ${purchase.error?.message}');
    onPurchaseError?.call('Purchase failed: ${purchase.error?.message}');
    _purchasePending = false;
    onPurchaseProcessing?.call(false);
  }

  Future<void> _handleSuccess(PurchaseDetails purchase) async {
    print('Purchase successful: ${purchase.productID}');

    if (purchase.pendingCompletePurchase) {
      try {
        final String platform = Platform.isIOS ? 'ios' : 'android';

        // 1. Verify the purchase receipt/token with your backend.
        // This is CRITICAL for security and to ensure the purchase is legitimate.
        final verificationResult = await BackendApiService.verifyInAppPurchase(
          platform: platform,
          productId: purchase.productID,
          verificationData: purchase.verificationData.serverVerificationData,
          transactionId: purchase.transactionID, // transactionID is relevant for iOS
        );

        if (verificationResult['success'] == true) {
          print('Backend verification successful for ${purchase.productID}');
          // 2. Deliver content/update user entitlements on your backend.
          // (This step would typically be part of the `verifyInAppPurchase` backend call).

          // 3. Complete the purchase on the store side.
          await _iap.completePurchase(purchase);

          // 4. Acknowledge the purchase on Google Play for Android.
          // This must happen within 3 days of a successful purchase.
          // Best done after content delivery and `completePurchase`.
          if (Platform.isAndroid && purchase.verificationData.serverVerificationData != null) {
            await BackendApiService.acknowledgePurchase(
              platform: 'android',
              purchaseToken: purchase.verificationData.serverVerificationData,
              productId: purchase.productID,
            );
          }

          onPurchaseSuccess?.call(purchase);
        } else {
          print('Backend verification failed for ${purchase.productID}: ${verificationResult['message']}');
          onPurchaseError?.call('Purchase verification failed.');
          // Do NOT complete purchase if backend verification fails.
          // This allows the purchase to remain pending and be re-evaluated.
        }
      } catch (e) {
        print('Error during backend verification or content delivery: $e');
        onPurchaseError?.call('Internal error processing purchase: $e');
        // Do NOT complete purchase if backend interaction fails.
      }
    }
    _purchasePending = false;
    onPurchaseProcessing?.call(false);
  }

  Future<void> buyProduct(ProductDetails product) async {
    if (!_isAvailable) {
      onPurchaseError?.call('In-App Purchase not available.');
      return;
    }
    if (_purchasePending) {
      onPurchaseError?.call('A purchase is already pending. Please wait.');
      return;
    }

    final PurchaseParam purchaseParam = PurchaseParam(productDetails: product);
    try {
      _purchasePending = true;
      onPurchaseProcessing?.call(true);
      // Use the appropriate buy method based on your product type
      final bool started = await _iap.buyNonConsumable(purchaseParam: purchaseParam);
      // For consumables: await _iap.buyConsumable(purchaseParam: purchaseParam);
      // For subscriptions: await _iap.buySubscription(purchaseParam: purchaseParam);

      if (!started) {
        _purchasePending = false;
        onPurchaseProcessing?.call(false);
        onPurchaseError?.call('Failed to start purchase process (e.g., user cancelled before native dialog).');
      }
    } catch (e) {
      _purchasePending = false;
      onPurchaseProcessing?.call(false);
      onPurchaseError?.call('Error initiating purchase: $e');
    }
  }

  void dispose() {
    _purchaseStreamSubscription.cancel();
  }
}

// --- 4. Payment Module (Main Widget) ---
class PaymentModuleScreen extends StatefulWidget {
  const PaymentModuleScreen({Key? key}) : super(key: key);

  @override
  State<PaymentModuleScreen> createState() => _PaymentModuleScreenState();
}

class _PaymentModuleScreenState extends State<PaymentModuleScreen> {
  final IAPService _iapService = IAPService();
  String? _statusMessage;
  bool _isLoading = false;
  bool _isIAPPending = false;

  @override
  void initState() {
    super.initState();
    _initPaymentServices();
  }

  Future<void> _initPaymentServices() async {
    setState(() {
      _isLoading = true;
      _statusMessage = 'Initializing payment services...';
    });

    try {
      await StripeService.init();
      print('Stripe initialized.');

      _iapService.onPurchaseSuccess = _handleIAPSuccess;
      _iapService.onPurchaseError = _handleIAPError;
      _iapService.onPurchaseProcessing = (isPending) {
        setState(() => _isIAPPending = isPending);
      };
      await _iapService.init();
      print('IAP Service initialized.');

      setState(() {
        _isLoading = false;
        _statusMessage = 'Payment services ready.';
      });
    } catch (e) {
      setState(() {
        _isLoading = false;
        _statusMessage = 'Failed to initialize payment services: $e';
      });
      _showSnackBar('Initialization Failed: $e', isError: true);
    }
  }

  void _handleIAPSuccess(PurchaseDetails purchase) {
    setState(() {
      _statusMessage = 'IAP Success: ${purchase.productID}';
    });
    _showSnackBar('Purchase successful: ${purchase.productID}');
  }

  void _handleIAPError(String errorMessage) {
    setState(() {
      _statusMessage = 'IAP Error: $errorMessage';
    });
    _showSnackBar('Purchase error: $errorMessage', isError: true);
  }

  void _showSnackBar(String message, {bool isError = false}) {
    ScaffoldMessenger.of(context).showSnackBar(
      SnackBar(
        content: Text(message),
        backgroundColor: isError ? Colors.red.shade700 : Colors.green.shade700,
      ),
    );
  }

  @override
  void dispose() {
    _iapService.dispose();
    super.dispose();
  }

  @override
  Widget build(BuildContext context) {
    return Scaffold(
      appBar: AppBar(title: const Text('Payment Module')),
      body: Center(
        child: SingleChildScrollView(
          padding: const EdgeInsets.all(16.0),
          child: Column(
            mainAxisAlignment: MainAxisAlignment.center,
            children: [
              if (_isLoading)
                const CircularProgressIndicator()
              else
                Column(
                  children: [
                    Text(
                      _statusMessage ?? '',
                      textAlign: TextAlign.center,
                      style: const TextStyle(fontSize: 16),
                    ),
                    const SizedBox(height: 30),
                    const Text('Stripe Payments:', style: TextStyle(fontSize: 18, fontWeight: FontWeight.bold)),
                    const SizedBox(height: 15),
                    ElevatedButton(
                      onPressed: () async {
                        setState(() => _isLoading = true);
                        try {
                          final success = await StripeService.processWalletPayment(
                            amount: 2000, // $20.00 in cents
                            currency: 'USD',
                          );
                          setState(() {
                            _statusMessage = success ? 'Wallet Payment Successful!' : 'Wallet Payment Failed.';
                            _isLoading = false;
                          });
                          _showSnackBar(_statusMessage!, isError: !success);
                        } catch (e) {
                          setState(() {
                            _statusMessage = 'Error processing wallet payment: $e';
                            _isLoading = false;
                          });
                          _showSnackBar('Error: $e', isError: true);
                        }
                      },
                      child: const Text('Pay with Apple Pay / Google Pay ($20.00)'),
                    ),
                    const SizedBox(height: 10),
                    ElevatedButton(
                      onPressed: () async {
                        setState(() => _isLoading = true);
                        try {
                          final success = await StripeService.processCardPayment(
                             amount: 1500, // $15.00 in cents
                             currency: 'USD',
                          );
                          setState(() {
                            _statusMessage = success ? 'Card Payment via PaymentSheet Successful!' : 'Card Payment via PaymentSheet Failed.';
                            _isLoading = false;
                          });
                          _showSnackBar(_statusMessage!, isError: !success);
                        } catch (e) {
                          setState(() {
                            _statusMessage = 'Error processing card payment: $e';
                            _isLoading = false;
                          });
                          _showSnackBar('Error: $e', isError: true);
                        }
                      },
                      child: const Text('Pay with Card (Stripe PaymentSheet) ($15.00)'),
                    ),
                    const SizedBox(height: 30),
                    const Text('In-App Purchases:', style: TextStyle(fontSize: 18, fontWeight: FontWeight.bold)),
                    const SizedBox(height: 15),
                    if (!_iapService.isAvailable)
                      const Text('In-App Purchases are not available on this device.')
                    else if (_iapService.availableProducts.isEmpty)
                      const Text('Loading products or no IAP products found.')
                    else
                      ..._iapService.availableProducts.map((product) {
                        return Padding(
                          padding: const EdgeInsets.symmetric(vertical: 8.0),
                          child: ElevatedButton(
                            onPressed: _isIAPPending || _isLoading
                                ? null
                                : () async {
                                    _iapService.buyProduct(product);
                                    // UI update will be handled by IAPService's callbacks
                                  },
                            child: Text('${product.title} (${product.price})'),
                          ),
                        );
                      }).toList(),
                    if (_isIAPPending)
                      const Padding(
                        padding: EdgeInsets.all(16.0),
                        child: CircularProgressIndicator(),
                      ),
                  ],
                ),
            ],
          ),
        ),
      ),
    );
  }
}

